/**
 * Avatar Cache — Real hero artwork, square rounded frame.
 * Images cropped directly from the hero artwork sheet (160x160px).
 */

export type AvatarRequest = {
  templateId: string
  name: string
  role: string
  rarity: string
  origins: string[]
  isEnemy?: boolean
  flavor?: string
}

const memCache: Record<string, string> = {}

