  mage:     "data:image/svg+xml,%3Csvg viewBox='0 0 100 100' xmlns='http://www.w3.org/2000/svg'%3E%3Crect width='100' height='100' fill='%23f4f4f4'/%3E%3Cpath d='M50 8 L56 38 L82 44 L56 50 L62 80 L50 58 L38 80 L44 50 L18 44 L44 38Z' fill='%23555'/%3E%3C/svg%3E",
