function buildWrapper(req: AvatarRequest, imgSrc: string): string {
  const ring      = RARITY_RING[req.rarity] ?? RARITY_RING.common
  const hiRarity  = ["legendary", "mythic", "celestial"].includes(req.rarity)
  const topRarity = ["mythic", "celestial"].includes(req.rarity)
  const uid       = req.templateId.replace(/[^a-z0-9]/g, "") + (req.isEnemy ? "e" : "h")
  const bw        = hiRarity ? 5 : 3.5
  const r         = 10  // corner radius for rounded square

  return `<svg viewBox="0 0 100 100" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <defs>
    <clipPath id="sq${uid}">
      <rect x="3" y="3" width="94" height="94" rx="${r}" ry="${r}"/>
    </clipPath>
    ${hiRarity ? `<filter id="glow${uid}" x="-20%" y="-20%" width="140%" height="140%">
      <feGaussianBlur stdDeviation="2.5" result="blur"/>
      <feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>
    </filter>` : ""}
  </defs>

  <!-- Dark background -->
  <rect x="0" y="0" width="100" height="100" rx="${r + 2}" ry="${r + 2}" fill="#1c1d22"/>

  <!-- Hero artwork clipped to rounded square -->
  <image href="${imgSrc}" x="3" y="3" width="94" height="94"
    clip-path="url(#sq${uid})" preserveAspectRatio="xMidYMid slice"/>

  <!-- Rarity border (rounded square) -->
  <rect x="2" y="2" width="96" height="96" rx="${r + 1}" ry="${r + 1}"
    fill="none" stroke="${ring}" stroke-width="${bw}" opacity="0.95"
    ${hiRarity ? `filter="url(#glow${uid})"` : ""}/>

  <!-- Inner subtle border -->
  <rect x="5.5" y="5.5" width="89" height="89" rx="${r - 1}" ry="${r - 1}"
    fill="none" stroke="${ring}" stroke-width="0.8" opacity="0.2"/>

  ${hiRarity ? `
  <!-- Corner gems for high rarity -->
  <circle cx="50" cy="1.5"  r="2.5" fill="${ring}" opacity="0.95"/>
  <circle cx="50" cy="98.5" r="2.5" fill="${ring}" opacity="0.95"/>
  <circle cx="1.5"  cy="50" r="2.5" fill="${ring}" opacity="0.95"/>
  <circle cx="98.5" cy="50" r="2.5" fill="${ring}" opacity="0.95"/>` : ""}
  ${topRarity ? `<path d="M44 1 L50 7 L56 1" fill="none" stroke="${ring}" stroke-width="2.5" stroke-linecap="round"/>` : ""}
</svg>`
}

export function getAvatar(req: AvatarRequest): string | null {
  const key = req.templateId + (req.isEnemy ? "_e" : "_h")
  if (memCache[key]) return memCache[key]
  const imgSrc = HERO_IMAGES[req.templateId] ?? ROLE_SVG[req.role] ?? ROLE_SVG.warrior
  const svg    = buildWrapper(req, imgSrc)
  memCache[key] = svg
  return svg
}

export async function preloadAvatars(requests: AvatarRequest[]): Promise<void> {
  for (const req of requests) getAvatar(req)
}

export function svgToDataUrl(svg: string): string {
  return "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg)
}
